How-To-Repeat: $ cc -Wall -Wextra -O ftstest.c -o ftstest
(Compile the test program below.)
$ mkdir x
$ ./ftstest x/
level: 0 path: x/ info: 1
level: 0 path: x info: 6
(Notice missing trailing slash in post-order.)

%%%
#include <sys/stat.h>
#include <sys/types.h>

#include <fts.h>
#include <stdio.h>

int
main(int argc, char **argv)
{
	FTS *fts;
	FTSENT *ftsent;
	char *fts_argv[] = {".", NULL};

	if (argc == 2)
		fts_argv[0] = argv[1];

	fts = fts_open(fts_argv, FTS_NOCHDIR | FTS_PHYSICAL, NULL);

	while ((ftsent = fts_read(fts)) != NULL) {
		printf("level: %ld path: %s info: %d\n",
		    (long)ftsent->fts_level,
		    ftsent->fts_path,
		    ftsent->fts_info);
	}

	fts_close(fts);

	return (0);
}
